<template>
	<view>
		<view class="goods-template">
			<scroll-view scroll-y>

				<view class="list" style="margin-bottom: 20rpx;">
					<view class="item" >
						<view class="header">
							<image class="img" v-if="item.img" :src="item.img" mode="aspectFit"></image>
							<view class="name">
								<view class="text" :style="{
									color:item.color
								}">
									{{item.title}}
								</view>
								<view class="time">
									{{ $util.timeFormat(item.create_time,'yyyy-mm-dd hh:MM:ss') }}
								</view>
							</view>
						</view>
						<view class="title">

						</view>
						<view class="content">
							<u-parse :html="item.content"></u-parse>
						</view>

					</view>
				</view>
				
			</scroll-view>
		</view>


	</view>
</template>

<script>
	export default {
		data() {
			return {
				id: 0,
				activeColor: '#f06c7a',
				inactiveColor: '#606266',
				item: {},
				type: 0,
				status: 'loadmore',
				iconType: 'flower',
				loadText: {
					loadmore: '上拉加载',
					loading: '努力加载中',
					nomore: '实在没有了'
				},


				loaded: false,
			};
		},
		onLoad(e) {

			if (e.type) {
				this.type = e.type
			} else {
				this.type = 1
			}

			if (e.id) {
				this.id = e.id
				this.loadData();
			}



		},
		methods: {
			async loadData() {

				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				this.$u.api.noticeDetail({
						type: this.type,
						id: this.id,

					})
					.then(res => {
						this.item = res
						console.log(res);
						this.loaded = true
					}).catch(res => {})
				uni.hideLoading()
			},

		}
	}
</script>

<style lang="scss" scoped>
	page {
		background-color: #f5f7fa;
		height: 100%;
	}

	.goods-template {
		width: 100%;
		height: 100%;
		// position: fixed;
		top: 0;
		left: 0;
		overflow: hidden;
	}

	.list {
		width: 100%;
		display: flex;
		flex-direction: column;
		align-items: center;
		justify-content: flex-start;
		gap: 16rpx;
		margin-top: 20rpx;
	}

	.list .item {
		display: flex;
		flex-direction: column;
		// align-items: center;
		justify-content: flex-start;
		width: 714rpx;
		border-radius: 10rpx;
		background: #FFFFFF;
		padding: 30rpx 20rpx;
		box-sizing: border-box;
	}

	.list .item .header {
		width: 100%;
		display: flex;
		align-items: flex-start;
		justify-content: flex-start;
		gap: 20rpx;
	}

	.list .item .header .img {
		width: 88rpx;
		height: 88rpx;
		border-radius: 50%;
	}

	.list .item .header .name {
		flex: 1;
		height: 80rpx;
		display: flex;
		flex-direction: column;
		justify-content: space-between;
		align-items: flex-start;
	}

	.list .item .title {
		width: 100%;
		font-size: 30rpx;
		font-family: PingFangSC-Medium, PingFang SC;
		font-weight: 500;
		color: #1e2331;
		margin-top: 24rpx;
		white-space: pre-line;
	}

	.list .item .header .name .text {
		font-size: 28rpx;
		font-family: PingFangSC-Medium, PingFang SC;
		font-weight: 500;
		color: #1e2331;
	}

	.list .item .header .name .time {
		font-size: 24rpx;
		font-family: PingFangSC-Regular, PingFang SC;
		font-weight: 400;
		color: #9b9fa8;
	}
</style>
